text:
{{
  inpQuantity.text && inpPurchaseCost.text
    ? "Cost / unit " + (() => {
        const qty = Number(inpQuantity.text);
        const cost = Number(inpPurchaseCost.text);
        const wastage = Number(inpWastage.text || 0);

        const netYield = qty * (1 - wastage / 100);

        if (!netYield || netYield <= 0) return "";

        const v = cost / netYield;
        const price = v % 1 === 0 ? v.toFixed(0) : v.toFixed(2);
        const unit = selPurchaseUnit.selectedOptionLabel || "";

        return unit ? `$${price} / ${unit}` : `$${price}`;
      })()
    : "Cost / unit "
}}
